// pages/Quiz.jsx — Timed quiz with score result
import React, { useState } from "react";
import { TOPICS } from "../data/topicsData";
import { useAI } from "../hooks/useAI";
import { saveQuizScore } from "../utils/progress";

export default function Quiz() {
  const [selectedSlug, setSelectedSlug] = useState(TOPICS[0].slug);
  const [questions, setQuestions] = useState([]);
  const [answers, setAnswers] = useState({});   // { questionId: selectedOption }
  const [submitted, setSubmitted] = useState(false);
  const [score, setScore] = useState(0);
  const [useAIQuiz, setUseAIQuiz] = useState(false);

  const { generateQuiz, loading, error } = useAI();

  const topic = TOPICS.find((t) => t.slug === selectedSlug);

  // Load local questions or generate via AI
  const startQuiz = async () => {
    setSubmitted(false);
    setAnswers({});
    setScore(0);

    if (useAIQuiz) {
      const aiQs = await generateQuiz(topic.name, 8);
      if (aiQs) setQuestions(aiQs.map((q, i) => ({ ...q, id: q.id ?? i })));
    } else {
      // Use all local questions across topics — combine for a mixed quiz
      const local = TOPICS.flatMap((t) =>
        t.questions.map((q) => ({ ...q, id: `${t.slug}-${q.id}`, topicName: t.name }))
      );
      // Pick 8 random questions
      const shuffled = local.sort(() => Math.random() - 0.5).slice(0, 8);
      setQuestions(shuffled);
    }
  };

  const handleSelect = (qId, option) => {
    if (submitted) return;
    setAnswers((prev) => ({ ...prev, [qId]: option }));
  };

  const handleSubmit = () => {
    if (questions.length === 0) return;
    let correct = 0;
    questions.forEach((q) => {
      if (answers[q.id] === q.answer) correct++;
    });
    setScore(correct);
    setSubmitted(true);
    saveQuizScore(topic.name, correct, questions.length);
  };

  const pct = questions.length > 0 ? Math.round((score / questions.length) * 100) : 0;

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">
      <h1 className="text-xl font-semibold text-white mb-1">Quiz</h1>
      <p className="text-sm text-muted mb-8">
        Test yourself — all questions are multiple choice.
      </p>

      {/* Controls */}
      <div className="flex flex-col sm:flex-row gap-4 mb-8">
        <div>
          <label className="block text-xs font-mono text-muted mb-1 uppercase tracking-widest">
            Topic
          </label>
          <select
            value={selectedSlug}
            onChange={(e) => { setSelectedSlug(e.target.value); setQuestions([]); }}
            className="bg-surface border border-border text-sm text-gray-300 rounded px-3 py-2 focus:outline-none focus:border-accent w-full"
          >
            {TOPICS.map((t) => (
              <option key={t.slug} value={t.slug}>{t.name}</option>
            ))}
          </select>
        </div>

        <div className="flex items-end gap-3">
          <label className="flex items-center gap-2 text-sm text-gray-400 cursor-pointer">
            <input
              type="checkbox"
              checked={useAIQuiz}
              onChange={(e) => setUseAIQuiz(e.target.checked)}
              className="accent-accent"
            />
            Use AI questions
          </label>
        </div>

        <div className="flex items-end">
          <button
            onClick={startQuiz}
            disabled={loading}
            className="bg-accent hover:bg-accent-hover text-white text-sm px-5 py-2 rounded transition-colors disabled:opacity-50"
          >
            {loading ? "Loading…" : questions.length ? "Restart" : "Start Quiz"}
          </button>
        </div>
      </div>

      {error && <p className="text-xs text-red-400 mb-4">AI Error: {error}</p>}

      {/* Questions */}
      {questions.length > 0 && (
        <>
          <div className="border-t border-border mb-6" />
          <p className="text-xs font-mono text-muted mb-6">
            {questions.length} questions — select one option per question
          </p>

          <div className="space-y-8">
            {questions.map((q, i) => {
              const selected = answers[q.id];
              const isCorrect = selected === q.answer;

              return (
                <div key={q.id} className="border-b border-border pb-6">
                  {q.topicName && (
                    <p className="text-xs text-muted font-mono mb-1">{q.topicName}</p>
                  )}
                  <p className="text-sm text-gray-200 mb-4 leading-relaxed">
                    <span className="text-muted font-mono mr-2">Q{i + 1}.</span>
                    {q.question}
                  </p>

                  <div className="space-y-2 pl-5">
                    {q.options.map((opt) => {
                      const letter = opt.charAt(0);
                      const isSelected = letter === selected;
                      const isAnswer = letter === q.answer;

                      let cls = "text-gray-400 hover:text-gray-200";
                      if (submitted) {
                        if (isAnswer) cls = "text-green-400 font-medium";
                        else if (isSelected) cls = "text-red-400 line-through";
                      } else if (isSelected) {
                        cls = "text-accent";
                      }

                      return (
                        <button
                          key={letter}
                          onClick={() => handleSelect(q.id, letter)}
                          className={`block text-left text-sm transition-colors ${cls}`}
                          disabled={submitted}
                        >
                          {opt}
                        </button>
                      );
                    })}
                  </div>

                  {submitted && (
                    <div className="mt-3 pl-5">
                      <span
                        className={`text-xs font-mono ${
                          isCorrect ? "text-green-500" : "text-red-400"
                        }`}
                      >
                        {isCorrect ? "✓ Correct" : `✗ Correct: ${q.answer}`}
                      </span>
                      {q.explanation && (
                        <p className="text-xs text-gray-500 mt-1">{q.explanation}</p>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Submit / Score */}
          {!submitted ? (
            <button
              onClick={handleSubmit}
              className="mt-8 bg-accent hover:bg-accent-hover text-white text-sm px-6 py-2.5 rounded transition-colors"
            >
              Submit Quiz
            </button>
          ) : (
            <div className="mt-8 border-t border-border pt-6">
              <p className="text-sm text-gray-300 mb-1">
                Score:{" "}
                <span className="text-white font-semibold">
                  {score} / {questions.length}
                </span>
              </p>
              <p className="text-xs text-muted">
                {pct >= 80
                  ? "🎉 Excellent work!"
                  : pct >= 50
                  ? "📚 Good effort, keep practicing."
                  : "💪 Keep going — review the topics."}
              </p>
            </div>
          )}
        </>
      )}

      <div className="h-16" />
    </main>
  );
}
